import Foundation

enum Environment {
    case development
    case staging
    case production
}

class NetworkManager {
    static let shared = NetworkManager()
    private let session = URLSession.shared
    private var baseURL: String {
        switch currentEnvironment {
        case .development: return "https://dev.api.example.com"
        case .staging: return "https://staging.api.example.com"
        case .production: return "https://api.example.com"
        }
    }
    
    var currentEnvironment: Environment = .production
    
    private init() {}
    
    func performGETRequest(endpoint: String, completion: @escaping (Data?, URLResponse?, Error?) -> Void) {
        guard let url = URL(string: "\(baseURL)\(endpoint)") else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        let dataTask = session.dataTask(with: request, completionHandler: completion)
        dataTask.resume()
    }
    
    func performPOSTRequest(endpoint: String, parameters: [String: Any], completion: @escaping (Data?, URLResponse?, Error?) -> Void) {
        guard let url = URL(string: "\(baseURL)\(endpoint)") else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: parameters, options: [])
        } catch let error {
            completion(nil, nil, error)
            return
        }
        
        let dataTask = session.dataTask(with: request, completionHandler: completion)
        dataTask.resume()
    }
}

// Usage example
NetworkManager.shared.currentEnvironment = .staging

NetworkManager.shared.performGETRequest(endpoint: "/user") { data, response, error in
    if let error = error {
        print("GET Request Error: \(error)")
    } else if let data = data {
        print("GET Response Data: \(data)")
    }
}

NetworkManager.shared.performPOSTRequest(endpoint: "/authenticate", parameters: ["username": "user", "password": "pass"]) { data, response, error in
    if let error = error {
        print("POST Request Error: \(error)")
    } else if let data = data {
        print("POST Response Data: \(data)")
    }
}